INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(10, 'Back in Black', 'Back in Black é o sétimo álbum de estúdio da banda australiana AC/DC, lançado em 25 de julho de 1980. Ele é um dos discos mais icônicos da história do rock — tanto pelo som marcante quanto pela história por trás da sua criação.', , '2025-11-04');
INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(13, 'The Dark Side of the Moon', 'The Dark Side of the Moon é o oitavo álbum de estúdio da banda britânica Pink Floyd, lançado em 1º de março de 1973. É considerado uma das obras mais importantes e influentes da história da música. O disco combina rock progressivo, experimentalismo sonoro e reflexões filosóficas sobre temas universais como o tempo, a loucura, o dinheiro, a alienação e a mortalidade.', , '2025-11-05');
INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(21, 'Traveling Without Moving', 'Traveling Without Moving (1996), do Jamiroquai, é um álbum que mistura acid jazz, funk e disco com muita energia, destacando grooves dançantes e uma estética inspirada em velocidade e futurismo. Com hits como “Virtual Insanity” e “Cosmic Girl”, tornou-se um dos trabalhos mais marcantes da banda e um ícone do pop dos anos 90.', , '2025-11-10');
INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(22, 'Animals', 'Animals (1977), do Pink Floyd, é um álbum conceitual que critica a sociedade industrial e capitalista por meio de metáforas com animais — cachorros, porcos e ovelhas — inspiradas em A Revolução dos Bichos, de George Orwell. Com faixas longas, arranjos intensos e um tom mais agressivo que outros trabalhos da banda, o disco destaca guitarras marcantes de David Gilmour e letras duras de Roger Waters. O resultado é uma obra sombria, poderosa e altamente simbólica, que reflete conflitos sociais e hum', , '2025-11-10');
INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(23, 'The Wall', 'The Wall (1979), do Pink Floyd, é um álbum conceitual que acompanha a história de Pink, um músico que constrói um “muro” emocional para se isolar do mundo após traumas pessoais, pressões sociais e experiências dolorosas. Combinando rock progressivo, elementos teatrais e forte carga narrativa, o disco apresenta faixas icônicas como “Another Brick in the Wall, Pt. 2”, “Comfortably Numb” e “Hey You”. A obra explora temas como alienação, abuso, guerra e identidade, resultando em um dos projetos mais', , '2025-11-10');
INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(24, 'Abbey Road', 'Abbey Road (1969), dos Beatles, é um dos álbuns mais emblemáticos da banda, marcado por sua produção refinada, harmonias impecáveis e pela fusão de estilos que vai do rock ao pop psicodélico. O disco traz clássicos como “Come Together”, “Something” e o famoso medley do lado B, uma sequência de músicas conectadas que mostra a maturidade e coesão criativa do grupo. Com sua icônica capa na faixa de pedestres da Abbey Road, o álbum representa o auge artístico dos Beatles e permanece como um marco du', , '2025-11-10');
INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(25, 'Sgt. Pepper\'s Lonely Hearts Club Band', 'Sgt. Pepper\'s Lonely Hearts Club Band (1967), dos Beatles, é um álbum revolucionário que marcou uma virada na história da música ao misturar rock, psicodelia e elementos orquestrais com grande liberdade experimental. Criado como se fosse a apresentação de uma banda fictícia, o disco explora temas variados e usa arranjos sofisticados, efeitos de estúdio inovadores e letras mais simbólicas e imaginativas. Com faixas como “Lucy in the Sky with Diamonds”, “With a Little Help from My Friends” e “A Da', , '2025-11-10');
INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(26, 'Appetite for Destruction', 'Appetite for Destruction (1987), do Guns N’ Roses, é um álbum explosivo que combina hard rock cru, atitude rebelde e performances intensas, definindo o som do rock no final dos anos 80. Com riffs marcantes de Slash, a voz rasgada e agressiva de Axl Rose e letras que exploram excessos, violência urbana e vulnerabilidade emocional, o disco apresenta uma energia visceral e autêntica. Traz clássicos como “Welcome to the Jungle”, “Sweet Child o’ Mine” e “Paradise City”, tornando-se um dos álbuns de e', , '2025-11-10');
INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(27, 'Use Your Illusion I', 'Use Your Illusion I (1991), do Guns N’ Roses, é um álbum ambicioso que expande o som cru do grupo ao mesclar hard rock, baladas grandiosas e elementos de blues e piano. Com uma produção mais elaborada, o disco destaca a versatilidade da banda em faixas intensas como “November Rain”, carregada de emoção e orquestração, e músicas energéticas como “Don’t Cry” e “Live and Let Die”. A obra revela uma fase mais madura e expansiva do Guns N’ Roses, equilibrando agressividade e sensibi', , '2025-11-10');
INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(28, 'Thriller', 'Thriller (1982), de Michael Jackson, é um dos álbuns mais influentes e bem-sucedidos da história da música, combinando pop, R&B, funk e rock com uma produção inovadora de Quincy Jones. Com vocais marcantes, arranjos sofisticados e uma estética sonora moderna para a época, o disco traz clássicos como “Billie Jean”, “Beat It” e a faixa-título “Thriller”, cujo videoclipe revolucionou a indústria. A mistura de energia, carisma e experimentação consolidou Michael Jackson como o “Rei do Pop” e transfo', , '2025-11-10');
INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(30, 'Wish you were here', 'Wish You Were Here (1975), do Pink Floyd, é um álbum profundamente emocional que reflete sobre ausência, alienação e a pressão da indústria musical. Dedicado ao ex-membro Syd Barrett, o disco combina longas paisagens sonoras com letras introspectivas, destacando a suíte “Shine On You Crazy Diamond”, que funciona como um tributo melancólico e poderoso. Com arranjos atmosféricos, sintetizadores envolventes e guitarras expressivas de David Gilmour, o álbum cria uma experiência ime', , '2025-11-10');
INSERT INTO `servico` (`idServico`, `Nome`, `Descricao`, `Imagem`, `Data`) VALUES
(31, 'Led Zeppelin IV', 'Led Zeppelin IV (1971) é um dos álbuns mais icônicos da história do rock, combinando peso, misticismo e diversidade musical em uma obra sem título oficial. Com uma fusão única de hard rock, folk e elementos épicos, o disco destaca a química perfeita entre os integrantes do Led Zeppelin. Faixas como “Black Dog” e “Rock and Roll” exibem pura energia e virtuosismo, enquanto “The Battle of Evermore” e “Going to California” exploram um lado acústico e atmosférico. O ápice fica por conta de “Stairway ', , '2025-11-10');

